                ["NewSessionApprovalUntrusted"] = "\u0421\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c \u0434\u043b\u044f \u0440\u0438\u0441\u043a\u043e\u0432\u044b\u0445 \u043a\u043e\u043c\u0430\u043d\u0434",
