                ["NewSessionLocalProviderHelp"] = "\u042d\u0442\u043e \u043f\u043e\u043b\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0438 \u0432\u043a\u043b\u044e\u0447\u0435\u043d\u043d\u043e\u043c \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u043c OSS-\u0440\u0435\u0436\u0438\u043c\u0435. \u0417\u0434\u0435\u0441\u044c \u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f, \u043a \u043a\u0430\u043a\u043e\u043c\u0443 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0441\u0435\u0440\u0432\u0435\u0440\u0443 \u043c\u043e\u0434\u0435\u043b\u0435\u0439 \u0431\u0443\u0434\u0435\u0442 \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f Codex.",
                ["NewSessionLocalProviderNone"] = "\u0418\u0437 config / \u043d\u0435 \u0437\u0430\u0434\u0430\u043d",
                ["NewSessionLocalProviderNoneHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 provider \u0438\u0437 Codex config \u0438\u043b\u0438 \u043e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u043e\u0431\u044b\u0447\u043d\u044b\u0439 cloud-\u0440\u0435\u0436\u0438\u043c.",
                ["NewSessionLocalProviderLmStudioHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 LM Studio \u043a\u0430\u043a \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0435\u0440\u0432\u0435\u0440 \u0434\u043b\u044f open-source \u043c\u043e\u0434\u0435\u043b\u0435\u0439.",
                ["NewSessionLocalProviderOllamaHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 Ollama \u043a\u0430\u043a \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0435\u0440\u0432\u0435\u0440 \u0434\u043b\u044f open-source \u043c\u043e\u0434\u0435\u043b\u0435\u0439.",
                ["NewSessionFlagsHelp"] = "Search \u0434\u0430\u0435\u0442 web-\u043f\u043e\u0438\u0441\u043a, OSS \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0435\u0442 \u043d\u0430 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0433\u043e provider, \u0430 full-auto \u0432\u043a\u043b\u044e\u0447\u0430\u0435\u0442 \u0432\u0441\u0442\u0440\u043e\u0435\u043d\u043d\u044b\u0439 preset \u0434\u043b\u044f \u0443\u043f\u0440\u043e\u0449\u0435\u043d\u043d\u043e\u0433\u043e \u0437\u0430\u043f\u0443\u0441\u043a\u0430.",
                ["NewSessionPreviewHelp"] = "\u0417\u0434\u0435\u0441\u044c \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u0430 \u0442\u043e\u0447\u043d\u0430\u044f \u0438\u043d\u0442\u0435\u0440\u0430\u043a\u0442\u0438\u0432\u043d\u0430\u044f \u043a\u043e\u043c\u0430\u043d\u0434\u0430 Codex, \u043a\u043e\u0442\u043e\u0440\u0443\u044e AIHelper \u043e\u0442\u043f\u0440\u0430\u0432\u0438\u0442 \u0432 \u043d\u043e\u0432\u043e\u0435 \u043e\u043a\u043d\u043e \u0442\u0435\u0440\u043c\u0438\u043d\u0430\u043b\u0430.",
